import toast from "react-hot-toast";
import { CheckCircle } from "lucide-react";

export const showDeleteSuccessToast = (linkName = "Link") => {
  toast.custom((t) => (
    <div
      className={`
        flex items-center gap-4
        px-5 py-4
        min-w-[320px]
        rounded-xl
        bg-red-500
        backdrop-blur-xl
        border border-red-400/30
        shadow-[0_0_30px_rgba(239,68,68,0.25)]
        text-white
        transition-all duration-300
        ${t.visible ? "opacity-100 translate-y-0" : "opacity-0 -translate-y-2"}
      `}
    >
      {/* Icon */}
      <div className="flex items-center justify-center w-10 h-10 rounded-lg bg-red-500/20 border border-red-300/40">
        <CheckCircle className="text-white" size={20} />
      </div>

      {/* Text */}
      <div className="flex flex-col">
        <span className="text-sm font-semibold tracking-wide">
          Link Deleted Successfully
        </span>
        <span className="text-xs text-red-100">
          "{linkName}" has been deleted
        </span>
      </div>
    </div>
  ), {
    duration: 2200,
    position: "top-right",
  });
};
